<?phpnamespace App\Filament\Resources;use App\Filament\Resources\CouponResource\Pages;use App\Models\Coupon;use Filament\Forms;use Filament\Forms\Form;use Filament\Resources\Resource;use Filament\Tables;use Filament\Tables\Table;class CouponResource extends Resource{    protected static ?string $model = Coupon::class;    protected static ?string $navigationIcon = 'heroicon-o-ticket';    protected static ?string $navigationGroup = 'Orders & Billing';    protected static ?int $navigationSort = 4;    protected static ?string $navigationLabel = 'Coupons';    public static function form(Form $form): Form    {        return $form            ->schema([                Forms\Components\Section::make('Coupon Details')                    ->schema([                        Forms\Components\TextInput::make('code')                            ->required()                            ->maxLength(255)                            ->unique(ignoreRecord: true),                        Forms\Components\Select::make('type')                            ->options([                                'percentage' => 'Percentage',                                'fixed' => 'Fixed Amount',                            ])                            ->required()                            ->live(),                        Forms\Components\TextInput::make('value')                            ->numeric()                            ->required()                            ->suffix(fn ($get) => $get('type') === 'percentage' ? '%' : '$'),                        Forms\Components\TextInput::make('recurring')                            ->numeric()                            ->helperText('Number of invoices the discount applies to. Leave empty for unlimited.'),                        Forms\Components\TextInput::make('max_uses')                            ->numeric()                            ->helperText('Maximum number of times this coupon can be used. Leave empty for unlimited.'),                        Forms\Components\DatePicker::make('expires_at')                            ->label('Expires At'),                    ])->columns(2),                Forms\Components\Section::make('Products')                    ->schema([                        Forms\Components\Select::make('products')                            ->relationship('products', 'name')                            ->multiple()                            ->searchable()                            ->preload()                            ->helperText('Leave empty to apply to all products'),                    ]),            ]);    }    public static function table(Table $table): Table    {        return $table            ->columns([                Tables\Columns\TextColumn::make('code')                    ->sortable()                    ->searchable()                    ->weight('bold'),                Tables\Columns\TextColumn::make('type')                    ->badge()                    ->color(fn (string $state): string => match ($state) {                        'percentage' => 'primary',                        'fixed' => 'success',                    }),                Tables\Columns\TextColumn::make('value')                    ->formatStateUsing(fn ($state, $record): string => $record->type === 'percentage' ? "{$state}%" : number_format($state, 2)),                Tables\Columns\TextColumn::make('uses')                    ->label('Used')                    ->sortable(),                Tables\Columns\TextColumn::make('max_uses')                    ->label('Max Uses')                    ->placeholder('Unlimited'),                Tables\Columns\TextColumn::make('expires_at')                    ->dateTime()                    ->placeholder('Never'),                Tables\Columns\IconColumn::make('expired')                    ->boolean()                    ->state(fn ($record): bool => $record->expires_at && $record->expires_at->isPast()),            ])            ->filters([                Tables\Filters\SelectFilter::make('type')                    ->options([                        'percentage' => 'Percentage',                        'fixed' => 'Fixed Amount',                    ]),            ])            ->actions([                Tables\Actions\ViewAction::make(),                Tables\Actions\EditAction::make(),            ])            ->bulkActions([                Tables\Actions\BulkActionGroup::make([                    Tables\Actions\DeleteBulkAction::make(),                ]),            ]);    }    public static function getRelations(): array    {        return [            //        ];    }    public static function getPages(): array    {        return [            'index' => Pages\ListCoupons::route('/'),            'create' => Pages\CreateCoupon::route('/create'),            'view' => Pages\ViewCoupon::route('/{record}'),            'edit' => Pages\EditCoupon::route('/{record}/edit'),        ];    }}